    #[test]
    fn op_order_changes_result_and_persists() {
        // Posterize-then-brightness vs brightness-then-posterize give different
        // pixels — proof the pipeline honors `order`.
        let base = Adjust {
            brightness: 0.25,
            posterize: 3.0,
            ..Default::default()
        };
        let mut post_first = base;
        post_first.order = [
            OpKind::Posterize,
            OpKind::Brightness,
            OpKind::Contrast,
            OpKind::Gamma,
            OpKind::Shadows,
            OpKind::Highlights,
            OpKind::Hue,
            OpKind::Saturation,
            OpKind::Vibrance,
            OpKind::Pixelate,
            OpKind::Sharpen,
            OpKind::Invert,
            OpKind::ColorBalance,
            OpKind::Dither,
            OpKind::Palette,
            OpKind::Scanlines,
            OpKind::Glow,
            OpKind::Vignette,
            OpKind::Phosphor,
        ];
        let mut bright_first = post_first;
        bright_first.order.swap(0, 1); // brightness now before posterize
        let src = vec![90u8, 90, 90, 255];
        let (mut a, mut b) = (src.clone(), src.clone());
        adjust_pixels(&mut a, 1, 1, &post_first);
        adjust_pixels(&mut b, 1, 1, &bright_first);
        assert_ne!(
            a, b,
            "reordering posterize vs brightness changes the result"
        );
        // Persisted order round-trips, and a garbage order falls back to a full set.
        assert_eq!(
            Adjust::default()
                .with_order(&post_first.order_to_u8())
                .order,
            post_first.order
        );
        assert_eq!(
            Adjust::default().with_order(&[99u8; 15]).order,
            Adjust::DEFAULT_ORDER,
            "unknown indices → default order, never a partial set"
        );
    }

    #[test]
    fn palette_op_position_changes_result() {
        // A remap that snaps every pixel to red=100; combined with +brightness.
        // Palette LAST: brightness first, then remap → exactly (100,0,0).
        let a = Adjust {
            brightness: 0.5,
            order: [
                OpKind::Brightness,
                OpKind::Contrast,
                OpKind::Gamma,
                OpKind::Shadows,
                OpKind::Highlights,
                OpKind::Posterize,
                OpKind::Hue,
                OpKind::Saturation,
                OpKind::Vibrance,
                OpKind::Pixelate,
                OpKind::Sharpen,
                OpKind::Invert,
                OpKind::ColorBalance,
                OpKind::Dither,
                OpKind::Palette,
                OpKind::Scanlines,
                OpKind::Glow,
                OpKind::Vignette,
                OpKind::Phosphor,
            ],
            ..Default::default()
        };
        // A single-color palette so the Palette op snaps every pixel to (100,0,0);
        // dither off and balance neutral so only brightness + the snap matter.
        let pal = [[100u8, 0, 0, 255]];
        let aux = PipeAux {
            dither_method: 0,
            dither_amount: 0.0,
            dither_custom: &[],
            dither_n: 0,
            dither_scale_x: 1,
            dither_scale_y: 1,
            pixelate_h: 0.0,
            fx: PostFx::default(),
            balance: [0, 0, 0],
            palette: Some(&pal),
        };
        let mut last = vec![10u8, 20, 30, 255];
        apply_pipeline(&mut last, 1, 1, &a, &aux);
        assert_eq!(&last[0..3], &[100, 0, 0], "remap last wins outright");
        // Palette FIRST: remap to red=100, THEN brightness lifts it above 100.
        // (Palette is no longer last — 4 inactive post-FX ops trail it — so rotate the
        // Palette op to the front by its actual position.)
        let mut b = a;
        let pos = b.order.iter().position(|o| *o == OpKind::Palette).unwrap();
        b.order.rotate_left(pos);
        let mut first = vec![10u8, 20, 30, 255];
        apply_pipeline(&mut first, 1, 1, &b, &aux);
        assert!(
            first[0] > 100,
            "brightness after remap lifts the red channel"
        );
        assert_ne!(last, first, "moving the palette op changes the result");
    }

    #[test]
    fn fx_preset_serde_roundtrips_and_defaults_missing() {
        let p = FxPreset {
            name: "test".into(),
            color: Some([10, 20, 30]),
            quantize_on: true,
            quantize_n: 8,
            resize_on: true,
            resize_fx: 0.5,
            ..Default::default()
        };
        let json = serde_json::to_string(&p).unwrap();
        let back: FxPreset = serde_json::from_str(&json).unwrap();
        assert_eq!(back.name, "test");
        assert_eq!(back.color, Some([10, 20, 30]));
        assert_eq!(back.quantize_n, 8);
        assert!(back.resize_on);
        assert_eq!(back.resize_fx, 0.5);
        // #[serde(default)] fills fields a partial/older record omitted (dither_amount
        // defaults to 1.0, not f32's 0) — so old presets keep loading as the layout grows.
        let partial: FxPreset = serde_json::from_str(r#"{"name":"old"}"#).unwrap();
        assert_eq!(partial.name, "old");
        assert_eq!(partial.dither_amount, 1.0);
        assert_eq!(partial.quantize_n, 16);
    }

